async function main() {
  console.log('Seeding Ukrainian words...');
  
  for (const wordData of wordsData) {
    await prisma.word.create({
      data: {
        ukrainian: wordData.ukrainian,
        english: wordData.english,
        frequencyRank: wordData.frequencyRank,
        packNumber: wordData.packNumber,
      },
    });
  }

  console.log(`Seeded ${wordsData.length} words`);
  console.log(`Created ${Math.max(...wordsData.map(w => w.packNumber))} packs`);
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });
